class Solution:
    def minSteps(self, s: str, t: str) -> int:
        n = len(s)
        dp = [0] * n
        for i in range(1, n):
            for j in range(i):
                if s[j] != t[j]:
                    dp[i] = max(dp[i], dp[j] + 1)
        return dp[n - 1]

